param()
Set-Location "c:\ASK\MyWorkspace\sk-keys"
$d = "c:\ASK\MyWorkspace\sk-keys\dictionary\tier-5-distributed-architecture\SYD-system-design"

$gem   = [char]::ConvertFromUtf32(0x1F48E)
$bulb  = [char]::ConvertFromUtf32(0x1F4A1)
$brain = [char]::ConvertFromUtf32(0x1F9E0)
$link  = [char]::ConvertFromUtf32(0x1F517)
$star  = [char]0x2605
$empty = [char]0x2606

function Join-Lines { param([string[]]$lines) return $lines -join "`r`n" }

function Upgrade-SYD {
    param([string]$filename,[string]$newYaml,[string]$inventionMomentQuote,[string]$evolutionText,[string]$newRelatedContent,[string]$twContent,[string]$stContent,[string]$newThinkContent)
    $fp = "$d\$filename"
    $c = [System.IO.File]::ReadAllText($fp, [System.Text.Encoding]::UTF8)
    $nl = if ($c.Contains("`r`n")) { "`r`n" } else { "`n" }
    $fmEnd = $c.IndexOf("---", 4); $afterFm = $c.Substring($fmEnd + 3); $c = $newYaml + $afterFm
    if ($c.Contains($inventionMomentQuote)) {
        $c = $c.Replace($inventionMomentQuote, $inventionMomentQuote + $nl + $nl + "**EVOLUTION:**" + $nl + $evolutionText)
    } else { Write-Warning "Invention moment not found in $filename" }
    $rkHeader = "### $link Related Keywords"
    $rkPos = $c.IndexOf($rkHeader)
    if ($rkPos -ge 0) {
        $afterRk = $c.IndexOf("---", $rkPos + $rkHeader.Length)
        $c = $c.Substring(0, $rkPos) + $rkHeader + $nl + $nl + $newRelatedContent + $nl + $nl + $c.Substring($afterRk)
    } else { Write-Warning "Related Keywords not found in $filename" }
    $thinkHeader = "### $brain Think About This Before We Continue"
    $thinkPos = $c.IndexOf($thinkHeader)
    if ($thinkPos -ge 0) {
        $dashBefore = $c.LastIndexOf($nl + "---" + $nl, $thinkPos)
        $bodyPart = $c.Substring(0, $dashBefore)
        $c = $bodyPart + $nl + "---" + $nl + $nl + "### $gem Transferable Wisdom" + $nl + $nl + $twContent + $nl + $nl + "---" + $nl + $nl + "### $bulb The Surprising Truth" + $nl + $nl + $stContent + $nl + $nl + "---" + $nl + $nl + $thinkHeader + $nl + $nl + $newThinkContent + $nl
    } else { Write-Warning "Think section not found in $filename" }
    $c = $c.Replace("_Hint:_", "*Hint:*")
    [System.IO.File]::WriteAllText($fp, $c, [System.Text.Encoding]::UTF8)
    Write-Host "OK: $filename" -ForegroundColor Green
}

# ============================================================
# SYD-023 - Geo-Replication
# ============================================================
$yaml023 = Join-Lines @("---","id: SYD-023","title: Geo-Replication","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-022","used_by: SYD-024","related: SYD-024, SYD-020, SYD-022","tags:","  - distributed","  - advanced","  - reliability","  - architecture","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 23","permalink: /syd/geo-replication/","---")
$inv023 = '"Copy data to multiple geographic regions continuously. Users connect to nearest region (low latency). If one region fails, data survives in others."'
$evo023 = "Geo-replication began with tape-based offsite backup - a weekly truck would transport backup tapes to a physically distant site. Network replication replaced tape shipping in the 1990s, but latency over long-distance networks introduced replication lag. Cloud computing made geo-replication a managed service: RDS Multi-Region Read Replicas, Cosmos DB global distribution (30+ regions), and BigTable replication made cross-region data distribution a configuration choice rather than an engineering project. The discipline evolved from physical data portability to real-time synchronous and asynchronous replication at planetary scale."
$rk023 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-022 - Disaster Recovery]] - overall strategy; geo-replication is the data layer for cross-region DR","","**Builds On This (learn these next):**","- [[SYD-024 - Multi-Region Architecture]] - deployment pattern that uses geo-replication","","**Alternatives / Comparisons:**","- [[SYD-024 - Multi-Region Architecture]] - broader deployment pattern","- [[SYD-020 - Active-Active]] - can be implemented with geo-replication as the data layer")
$tw023 = Join-Lines @("**Reusable Engineering Principle:**","Distance plus latency equals a consistency trade-off. Any system that replicates data across geographic distance faces the fundamental choice: synchronous replication is consistent but slow (limited by speed of light), asynchronous replication is fast but eventually consistent. This trade-off appears in any distributed write: database replication, CDN cache propagation, DNS TTL, and repository mirroring. You cannot have both geographic distribution and zero replication lag.","","**Where else this pattern appears:**","- **CDN cache propagation:** When a file is updated at the origin, CDN edge nodes receive the update asynchronously - eventual consistency with TTL-based invalidation.","- **DNS propagation:** DNS record changes propagate to resolvers worldwide over 24-48 hours - the ultimate example of eventual consistency at planetary scale.","- **Git distributed workflow:** A git push replicates commits to remote asynchronously - developers in different offices work from eventually consistent views of the repository.")
$st023 = "The speed of light is the hard limit on geo-replication latency. New York to London is approximately 5,500 km. At the speed of light in fibre (~200,000 km/s), the minimum round-trip time is 55ms. In practice, because of routing overhead and packet processing, NY-London RTT is typically 70-80ms. This means synchronous geo-replication between these two regions adds at minimum 70ms to every write operation. This is not a software problem or an engineering problem - it is physics. No amount of software optimisation can make NY-London synchronous replication faster than the speed of light allows."
$think023 = Join-Lines @("**Q1.** You have geo-replication with 1-second lag. Users write. 0.5 seconds later, a different user (in different region) reads. What data do they see?","","*Hint:* Think about what 1-second lag means for a read that happens 0.5 seconds after a write - is the data present in the EU region at that moment? Explore what eventual consistency means for the specific user experience (stale reads) and whether read-your-own-writes consistency is achievable with replication lag.","","**Q2.** Multi-region write: Users in US and EU can both write to same document. Conflict possible. How do you resolve? Who wins?","","*Hint:* Think about what two regions simultaneously writing the same document means for the replication stream - does the EU region know about the US write before applying its own? Explore last-write-wins (LWW), vector clocks, and operational transformation (the algorithm Google Docs uses).","","**Q3 (System Interaction):** You're geo-replicating a user authentication database. A user changes their password in the EU region. 2 seconds later (before replication), they try to log in from their US-based mobile app using the new password. The US region still has the old hash. Authentication fails. How do you design around this?","","*Hint:* Think about what read-your-own-writes consistency requires and whether it can be achieved with asynchronous replication. Explore whether routing post-change reads to the write region (session-based routing), using synchronous replication for auth-critical writes, or a write token system that forces US reads to check EU would solve the problem.")
Upgrade-SYD "SYD-023 - Geo-Replication.md" $yaml023 $inv023 $evo023 $rk023 $tw023 $st023 $think023

# ============================================================
# SYD-024 - Multi-Region Architecture
# ============================================================
$yaml024 = Join-Lines @("---","id: SYD-024","title: Multi-Region Architecture","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-023, SYD-008, SYD-022","used_by:","related: SYD-023, SYD-020","tags:","  - distributed","  - advanced","  - architecture","  - reliability","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 24","permalink: /syd/multi-region-architecture/","---")
$inv024 = '"Deploy in multiple regions. Users route to nearest. Data center in each region survives continent-wide disasters."'
$evo024 = "Multi-region architecture began as an elite capability available only to internet giants. The 2010s democratised it: AWS expanded to 20+ regions, Route 53 latency routing made traffic distribution automatic, and managed databases offered cross-region replication. The discipline evolved from build-your-own-CDN engineering to a cloud service selection exercise. Today, Kubernetes Federation and service meshes extend multi-region deployment to application-level traffic management. The hard problems - data consistency, split-brain, and cost - remain and are now the primary concerns rather than the infrastructure plumbing."
$rk024 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-023 - Geo-Replication]] - the data replication strategy that multi-region requires","- [[SYD-008 - Load Balancing]] - distributes users across regions","- [[SYD-022 - Disaster Recovery]] - DR capability is a core benefit of multi-region","","**Builds On This (learn these next):**","- [[SYD-020 - Active-Active]] - deployment pattern used within multi-region architecture","","**Alternatives / Comparisons:**","- [[SYD-023 - Geo-Replication]] - data replication strategy used within multi-region","- [[SYD-020 - Active-Active]] - traffic pattern option within multi-region")
$tw024 = Join-Lines @("**Reusable Engineering Principle:**","System boundaries determine failure blast radius. A single-region system fails as a unit. A multi-region system can fail region by region. Draw boundaries where you want failures to stop. This applies to microservices (service boundaries contain failure), database sharding (shard boundaries contain data loss), and team organisation (team boundaries contain communication overhead). Blast radius is designed, not emergent.","","**Where else this pattern appears:**","- **Microservices bulkheads:** Separate thread pools per service prevent one slow service from exhausting all threads - blast radius is the thread pool boundary.","- **Database sharding:** A shard failure affects only users on that shard - blast radius is the shard boundary.","- **AWS Availability Zones:** Multiple AZs in a region ensure an AZ failure does not take down the region - blast radius is the AZ boundary.")
$st024 = "Multi-region architecture is often pursued for disaster recovery but delivers more value as a latency improvement. Moving computation close to users reduces latency by 50-200ms for global users. Most e-commerce research shows that a 100ms latency increase reduces conversion by 1%. A multi-region deployment reducing average global latency from 200ms to 50ms could yield 1-2% conversion improvement - often worth more than the disaster recovery benefit in pure business terms, even though DR is always the stated justification for the investment. Multi-region is frequently the right answer for the wrong reason."
$think024 = Join-Lines @("**Q1.** Multi-region system: write in US, read in EU within 1 second. Replication lag = 5 seconds. What data does EU user see? Is this acceptable?","","*Hint:* Think about what stale read means for a user who writes and reads in different regions within the replication window. Explore whether this is acceptable (user sees eventual updates) or unacceptable (user thinks their data was lost), and what client-side read-after-write guarantees require.","","**Q2.** You're building multi-region system. Budget allows only 2 regions (US and EU). Where should Asia traffic go? What are the tradeoffs?","","*Hint:* Think about routing: if US and EU are the only regions, where do Asia-Pacific users go? Explore the latency trade-off (AP to US: ~150ms vs AP to EU: ~250ms) and whether the architectural cost of a third region is justified by user volume and latency sensitivity in AP.","","**Q3 (Design Trade-off):** You're designing multi-region for a financial application. EU regulations require EU user data never leaves EU. US regulations require US financial data stays in the US. But the application needs to process cross-border payments between EU and US users. How do you architect data residency while supporting cross-border transactions?","","*Hint:* Think about what data residency means at the schema level - is it user PII (must stay regional) or transaction records (can be in both regions)? Explore whether the payment processing logic (stateless) can run in a neutral region while the user data remains in its home region.")
Upgrade-SYD "SYD-024 - Multi-Region Architecture.md" $yaml024 $inv024 $evo024 $rk024 $tw024 $st024 $think024

# ============================================================
# SYD-025 - Thundering Herd
# ============================================================
$yaml025 = Join-Lines @("---","id: SYD-025","title: Thundering Herd","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-008, SYD-028","used_by:","related: SYD-028, SYD-014","tags:","  - reliability","  - advanced","  - performance","  - architecture","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 25","permalink: /syd/thundering-herd/","---")
$inv025 = '"When system recovers, don''t let all clients retry at once. Stagger them. Gradually warm up the system."'
$evo025 = "Thundering herd was first documented in Unix kernel development in the early 1990s, where multiple processes would simultaneously wake up when a shared resource became available, causing CPU spikes and cache thrashing. The pattern was observed in web infrastructure when cache servers went down, causing all cache misses to simultaneously hit the origin database. Netflix's cache stampede during AWS outages (2012) brought the problem to wide engineering attention. Modern solutions (exponential backoff with jitter, cache lock, probabilistic early expiry) became standard practice after distributed systems papers documented the failure modes. The discipline evolved from OS kernel engineering to distributed systems resilience patterns."
$rk025 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-008 - Load Balancing]] - the layer that distributes the herd's load","- [[SYD-028 - Rate Limiting (System)]] - complementary protection against retry storms","","**Builds On This (learn these next):**","- [[SYD-014 - Auto Scaling]] - can amplify thundering herd if not carefully configured","","**Alternatives / Comparisons:**","- [[SYD-028 - Rate Limiting (System)]] - upstream protection; rate limiting prevents herds from forming","- [[SYD-014 - Auto Scaling]] - reactive capacity addition; auto-scaling responds to but does not prevent herds")
$tw025 = Join-Lines @("**Reusable Engineering Principle:**","Synchronisation is the enemy of distributed systems. When all clients perform the same action simultaneously (retry at the same moment, expire cache at the same time, wake up at the same interval), the load from that synchronisation spike can exceed system capacity. The solution is always to introduce randomness or distribution: jitter in retry intervals, staggered cache TTLs, randomised leader election timeouts. This principle applies to database lock granularity, batch job scheduling, and CI/CD pipeline triggers.","","**Where else this pattern appears:**","- **Exponential backoff:** AWS SDK retry logic adds jitter to exponential backoff - preventing all clients from retrying at exactly the same interval after a throttle.","- **Cache TTL jitter:** Adding random(0-10%) to cache TTL prevents mass simultaneous expiry - used by Varnish, Memcached, and Redis client libraries.","- **Kubernetes pod restart:** CrashLoopBackOff adds exponential delay between restarts - preventing a crash-looping pod from overwhelming the API server with restart requests.")
$st025 = "The thundering herd problem was independently discovered in three completely different domains before engineers recognised it as a single pattern. Unix kernel developers saw it in the accept() system call (multiple processes waking on one incoming connection). Cache engineers saw it as cache stampede (simultaneous cache misses hitting the origin). Mobile app engineers saw it as retry storm (apps retrying after server outage simultaneously). Each domain invented its own solution before distributed systems papers unified them as the same underlying synchronisation problem - a rare example of the same bug being independently fixed three times."
$think025 = Join-Lines @("**Q1.** Your service has 10,000 pending requests queued. It comes back online. Without backoff, all retry at once (10K req/sec spike). With exponential backoff, retries spread over 30 seconds. Which causes better user experience?","","*Hint:* Think about what all 10,000 retrying at once looks like for the database - what is the arrival rate, and how does it compare to pre-outage traffic? Explore whether the retry spike creates a second outage that prevents the system from recovering even though the root cause is fixed.","","**Q2.** You're implementing gradual warm-up. Acceptable load: 10% to 100% over 60 seconds. But if load increases to 50% capacity midway, do you speed up warm-up or keep the pace?","","*Hint:* Think about the difference between the rate of warm-up (10% capacity per interval) and the external load arriving (50% of capacity). Explore whether your warm-up schedule can be made adaptive (speed up when the system shows headroom) or whether a fixed schedule is safer to reason about.","","**Q3 (System Interaction):** Your application uses Redis for caching with a 60-second TTL. At exactly 60 seconds, 1,000 cached keys expire simultaneously (they were all loaded in a batch). All 1,000 cache misses hit your database simultaneously. Design a strategy to prevent this cache stampede.","","*Hint:* Think about when the synchronisation happened (batch load set all TTLs at the same time). Explore whether adding random jitter to TTL (60s plus/minus random(10s)) distributes expiry, probabilistic early refresh (refresh X seconds before expiry with probability proportional to staleness), or a distributed lock (only one thread refreshes, others wait) solves the problem.")
Upgrade-SYD "SYD-025 - Thundering Herd.md" $yaml025 $inv025 $evo025 $rk025 $tw025 $st025 $think025

# ============================================================
# SYD-026 - Back-of-Envelope Estimation
# ============================================================
$yaml026 = Join-Lines @("---","id: SYD-026","title: Back-of-Envelope Estimation","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$empty","depends_on: SYD-027","used_by: SYD-027","related: SYD-027","tags:","  - mental-model","  - foundational","  - architecture","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 26","permalink: /syd/back-of-envelope-estimation/","---")
$inv026 = '"Use mental math with rough numbers. 10^x orders of magnitude. Make assumptions explicit. Speed >> accuracy."'
$evo026 = "Back-of-envelope estimation predates computing - physicists like Enrico Fermi used it to estimate nuclear bomb yield at Trinity (1945) from the displacement of paper scraps. Engineers adapted Fermi estimation to computer systems in the 1960s. The system design interview format popularised it as a required engineering skill in the 2000s: Google, Amazon, and Facebook interview questions routinely included capacity estimation as a design exercise. The discipline evolved from physics estimation into a structured engineering communication skill taught in bootcamps and system design interview preparation courses worldwide."
$rk026 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-027 - Capacity Planning]] - formal capacity planning starts from back-of-envelope","","**Builds On This (learn these next):**","- [[SYD-027 - Capacity Planning]] - the disciplined follow-on to back-of-envelope estimation","- [[SYD-014 - Auto Scaling]] - auto-scaling parameters are informed by estimation","","**Alternatives / Comparisons:**","- [[SYD-027 - Capacity Planning]] - more detailed planning that refines back-of-envelope estimates")
$tw026 = Join-Lines @("**Reusable Engineering Principle:**","Order-of-magnitude reasoning is more useful than precise calculation for early design decisions. A 10x error in an estimate (1,000 vs 10,000 servers) matters; a 10% error (1,000 vs 1,100) does not at the design stage. This principle applies to project estimation (story points are powers of 2 by design), financial modelling (investors use round numbers for early-stage valuation), and architectural decisions (should I use a single database or shard it?). Get the magnitude right first; refine the coefficient later.","","**Where else this pattern appears:**","- **Project estimation:** T-shirt sizing (S/M/L/XL) or story points (1/2/3/5/8) are order-of-magnitude estimates - precise enough to plan sprints, not precise enough to commit to dates.","- **Infrastructure cost estimation:** Cloud architects estimate monthly cost to nearest $1K before detailed sizing - wrong in coefficient, right in magnitude.","- **SLA headroom calculations:** Calculating how many 9s of availability you can afford given your deployment frequency is a back-of-envelope calculation engineers do in design reviews.")
$st026 = "Enrico Fermi estimated the yield of the Trinity nuclear test at 10 kilotons by watching a piece of paper fall and drift in the blast wave. The actual yield was 18-20 kilotons - Fermi was within 2x. This legendary calculation demonstrated that systematic estimation from first principles is more valuable than computational tools when you do not have time for exact measurement. The same technique applied to server capacity works because computing resources scale by powers of 10: 1, 10, 100, 1,000 servers - the precision you need for architecture decisions is order-of-magnitude, not coefficient-level."
$think026 = Join-Lines @("**Q1.** YouTube has 2 billion users. If each user watches 1 hour/day at 1 Mbps, how much bandwidth globally?","","*Hint:* Think about units: users times hours/day times Mbps = total data. Convert to Tbps or Petabytes appropriately. Explore whether your calculation gives a reasonable answer by comparing to known CDN throughput numbers.","","**Q2.** Given peak QPS estimate, how would you validate it with real traffic patterns?","","*Hint:* Think about how peak traffic differs from average (2-10x for most consumer apps). Explore whether QPS validation requires instrumentation data or whether you can estimate it from product metrics (sessions per day, pages per session, API calls per page).","","**Q3 (Design Trade-off):** You estimate your system needs 100 servers. Your architect insists on 200 for headroom. A senior engineer says 50 is enough. How do you resolve this disagreement using back-of-envelope, and what metrics would you collect to validate post-deployment?","","*Hint:* Think about what assumptions each estimate is making (peak vs average load, headroom factor, single-threaded vs concurrent request handling). Explore how you would document your assumptions explicitly and what monitoring data would confirm or refute the estimate after launch.")
Upgrade-SYD "SYD-026 - Back-of-Envelope Estimation.md" $yaml026 $inv026 $evo026 $rk026 $tw026 $st026 $think026

# ============================================================
# SYD-027 - Capacity Planning
# ============================================================
$yaml027 = Join-Lines @("---","id: SYD-027","title: Capacity Planning","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-026","used_by: SYD-014","related: SYD-014, SYD-008, SYD-026","tags:","  - architecture","  - advanced","  - performance","  - observability","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 27","permalink: /syd/capacity-planning/","---")
$inv027 = '"Forecast growth rate. Track resource usage trends. Provision 6 months ahead. Smooth scaling."'
$evo027 = "Capacity planning began as a hardware procurement exercise - mainframe operators modelled workloads months in advance to order CPU and memory upgrades with long lead times. The cloud era transformed capacity planning from hardware ordering to auto-scaling configuration: instead of provisioning months ahead, teams configure scaling policies and let the cloud provision on-demand. The discipline evolved from a one-time procurement exercise to a continuous monitoring and forecasting practice. Modern capacity planning tools (Netflix's Scryer, Facebook's Capacity Planning Tool) use ML-based time-series forecasting to predict resource needs weeks in advance and auto-generate scaling recommendations."
$rk027 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-026 - Back-of-Envelope Estimation]] - estimation technique used to start a capacity plan","","**Builds On This (learn these next):**","- [[SYD-014 - Auto Scaling]] - reactive alternative; auto-scaling responds to load rather than forecasting it","","**Alternatives / Comparisons:**","- [[SYD-014 - Auto Scaling]] - reactive complement; auto-scaling handles unpredictable spikes that forecasting misses","- [[SYD-026 - Back-of-Envelope Estimation]] - estimation technique used within capacity planning")
$tw027 = Join-Lines @("**Reusable Engineering Principle:**","Plan for growth curves, not absolute numbers. Systems face seasonal spikes (Black Friday, back-to-school), sudden viral growth (product launch), and secular growth trends. Capacity planning that only handles the current trend misses spike scenarios. This principle appears in infrastructure provisioning (plan for 3x peak, not 1x average), team hiring (hire before the growth hits, not after), and product roadmaps (plan features for the user base 6 months from now, not today's users).","","**Where else this pattern appears:**","- **Database index planning:** Plan index capacity for 2x current data volume - indexes that fit in memory today may not fit in 6 months after growth.","- **API quota planning:** SaaS companies provision API rate limits at 10x average to absorb spikes - capacity planning for shared infrastructure.","- **Kubernetes resource requests/limits:** Setting resource requests above current usage but below maximum anticipated load is capacity planning at the pod level.")
$st027 = "Most capacity planning failures are not under-provisioning (the obvious failure) but over-provisioning (the invisible failure). AWS's own capacity studies estimate that enterprise customers use on average 30-40% of their provisioned cloud compute. Over-provisioned capacity is waste - it costs money and masks performance problems (a system running at 20% utilisation hides latency regressions until utilisation spikes). Teams that right-size aggressively discover performance issues faster because headroom is not available to absorb them. The correct capacity target is utilisation at 60-70% during peak, not 20-30%."
$think027 = Join-Lines @("**Q1.** Your system has 3-month provisioning lead time. CPU at 50%, growing 20%/month. When should you order new capacity?","","*Hint:* Think about the lead time for provisioning (3 months) and the growth rate (20%/month). When does CPU hit 70% (provisioning trigger)? Work backwards from the capacity limit, accounting for lead time, to find when you should order.","","**Q2.** Over-provisioning wastes money. Under-provisioning causes outages. How do you balance?","","*Hint:* Think about the cost of over-provisioning (paying for unused capacity) versus under-provisioning (SLA breach cost, revenue loss). Explore whether predictive auto-scaling (scale before you need to) or reserved capacity (pre-commit to a base level, scale above with on-demand) balances these costs.","","**Q3 (Scale):** You're building a capacity plan for a SaaS product that is 70% enterprise customers (predictable, contract-based load) and 30% self-serve customers (unpredictable, viral growth potential). Design a capacity strategy that handles both without over-provisioning for the self-serve spike.","","*Hint:* Think about whether enterprise capacity (predictable) can be provisioned with reserved instances (cheap, committed) while self-serve capacity (unpredictable) uses on-demand instances (flexible, costlier per hour). Explore how to monitor leading indicators of self-serve viral growth (signups/day, trial-to-paid conversion) to trigger proactive provisioning.")
Upgrade-SYD "SYD-027 - Capacity Planning.md" $yaml027 $inv027 $evo027 $rk027 $tw027 $st027 $think027

# ============================================================
# SYD-028 - Rate Limiting (System)
# ============================================================
$yaml028 = Join-Lines @("---","id: SYD-028","title: `"Rate Limiting (System)`"","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$empty","depends_on: SYD-008","used_by: SYD-029, SYD-030, SYD-044","related: SYD-029, SYD-030","tags:","  - performance","  - intermediate","  - architecture","  - reliability","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 28","permalink: /syd/rate-limiting-system/","---")
$inv028 = '"Limit requests per user per time window. User exceeds limit? Reject or queue."'
$evo028 = "Rate limiting began as a network-level concept in the 1970s - telephone switches rate-limited incoming calls to prevent network congestion. Web applications adopted rate limiting in the early 2000s as DDoS attacks became common. AWS API Gateway (2015) made managed rate limiting a service rather than a custom implementation. OAuth 2.0 and API management platforms standardised rate limit headers (X-RateLimit-Remaining, Retry-After). The discipline evolved from low-level network protection to a business policy tool: rate limits are now used for tiered pricing (free tier vs paid tier API limits) as much as for technical protection."
$rk028 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-008 - Load Balancing]] - the layer where rate limiting is typically enforced","","**Builds On This (learn these next):**","- [[SYD-029 - Token Bucket]] - one algorithm for implementing rate limits","- [[SYD-030 - Leaky Bucket]] - alternative algorithm with different burst characteristics","- [[SYD-044 - Rate Limiter Design]] - end-to-end system design using rate limiting","","**Alternatives / Comparisons:**","- [[SYD-029 - Token Bucket]] - implementation algorithm that allows bursts","- [[SYD-030 - Leaky Bucket]] - implementation algorithm that smooths output")
$tw028 = Join-Lines @("**Reusable Engineering Principle:**","Control the rate of work entering a system to protect its capacity. This principle appears everywhere: circuit breakers limit the rate of failure propagation, TCP congestion control limits the rate of packet sending, database connection pools limit the rate of concurrent queries. Every shared resource needs a rate controller, or the fastest client takes all resources.","","**Where else this pattern appears:**","- **TCP congestion control:** TCP's AIMD algorithm rate-limits packet sending based on network feedback - a rate limiter for network bandwidth.","- **Database connection pools:** Maximum pool size limits concurrent query rate - preventing one application from exhausting all database connections.","- **Kubernetes resource requests:** CPU requests limit the rate at which pods consume cluster CPU - pod-level rate limiting enforced by the kernel cgroups.")
$st028 = "Rate limiting has a business model dimension that is rarely discussed technically. Stripe, Twilio, and GitHub all use rate limits not primarily as protection mechanisms but as product packaging: the free tier gets 100 requests per minute, the paid tier gets 10,000 requests per minute. The rate limiter is the technical enforcement of the pricing policy. This means rate limiting code is revenue-critical infrastructure - a bug that grants free-tier users paid-tier access directly costs money. Rate limiting systems are tested more carefully than most engineers realise, because a single misconfiguration is a potential revenue loss of significant magnitude."
$think028 = Join-Lines @("**Q1.** Attacker has 100 IPs, each sends 100 req/min. Per-IP limit: 100 req/min (seems safe). How does attacker bypass?","","*Hint:* Think about the attacker's perspective: 100 IPs x 100 req/min = 10,000 req/min globally. Does per-IP rate limiting prevent this? Explore what a global rate limit (total requests per minute regardless of source) or account-level rate limit (tied to authenticated identity) would catch that per-IP limits miss.","","**Q2.** Legitimate user has traffic spike (3x normal). Rate limit rejects it. How do you handle?","","*Hint:* Think about what 3x normal looks like vs the configured limit - is the spike anticipated (a scheduled job, an email campaign going live) or random? Explore whether burst allowance (token bucket capacity), separate limit tiers for trusted clients, or proactive notification (rate limit approaching alert) handles legitimate spikes better than hard rejection.","","**Q3 (Design Trade-off):** You implement per-user rate limiting in a distributed API gateway with 5 nodes. Each node independently tracks a user's request count. A user sends 120 req/min across 5 nodes (24 per node). Per-node limit is 100 req/min. The user is never rate limited. Design a fix.","","*Hint:* Think about where the per-user state lives: each node has its own counter with no coordination. Explore whether centralising the counter in Redis solves the problem and what the latency and availability implications of that Redis dependency are.")
Upgrade-SYD "SYD-028 - Rate Limiting (System).md" $yaml028 $inv028 $evo028 $rk028 $tw028 $st028 $think028

